use aiken/collection/list
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

pub type MultiSigDatum {
  holders: List<ByteArray>,
  threshold: Int,
  nft_policy: ByteArray,
}

pub type MultiSigRedeemer {
  Spend
}

fn nft_policy_in_inputs(tx: Transaction, nft_policy: ByteArray) -> Bool {
  list.any(
    tx.inputs,
    fn(input) {
      let policy_assets = assets.tokens(input.output.value, nft_policy)
      !list.is_empty(assets.to_dict(policy_assets) |> fn(d) { assets.keys(d) })
    },
  )
}

fn check_nft_in_inputs(tx: Transaction, nft_policy: ByteArray) -> Bool {
  list.any(
    tx.inputs,
    fn(input) {
      let val = input.output.value
      let flattened = assets.flatten(val)
      list.any(
        flattened,
        fn(triple) {
          let (policy, _asset_name, qty) = triple
          policy == nft_policy && qty > 0
        },
      )
    },
  )
}

validator nft_multisig {
  spend(
    datum: Option<MultiSigDatum>,
    _redeemer: MultiSigRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let present =
          list.count(
            self.extra_signatories,
            fn(sig) { list.has(d.holders, sig) },
          )
        let threshold_met = present >= d.threshold
        let nft_present = check_nft_in_inputs(self, d.nft_policy)
        threshold_met && nft_present
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

pub type GuardDatum {
  signers: List<ByteArray>,
  threshold: Int,
  min_lovelace: Int,
}

pub type GuardRedeemer {
  recipient: ByteArray,
}

fn check_signers(
  signatories: List<ByteArray>,
  required: List<ByteArray>,
  threshold: Int,
) -> Bool {
  let present =
    list.count(signatories, fn(sig) { list.has(required, sig) })
  present >= threshold
}

fn check_min_lovelace(
  tx: Transaction,
  recipient: ByteArray,
  min_lovelace: Int,
) -> Bool {
  list.any(
    tx.outputs,
    fn(output) {
      let pays_to_recipient =
        when output.address.payment_credential is {
          cardano/address.VerificationKey(pkh) -> pkh == recipient
          _ -> False
        }
      let has_enough = assets.lovelace_of(output.value) >= min_lovelace
      pays_to_recipient && has_enough
    },
  )
}

validator guarded_multisig {
  spend(
    datum: Option<GuardDatum>,
    redeemer: GuardRedeemer,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let signers_ok =
          check_signers(self.extra_signatories, d.signers, d.threshold)
        let lovelace_ok =
          check_min_lovelace(self, redeemer.recipient, d.min_lovelace)
        signers_ok && lovelace_ok
      }
    }
  }

  else(_) {
    fail
  }
}
